import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { useUserAuth } from './UserAuth'; // Adjust the path if necessary
import { doc, getDoc } from "firebase/firestore"; // Firestore functions
import { db } from "./firebase"; // Firestore initialization
import './Header.css';

function Header() {
    const { user, signOutUser } = useUserAuth();
    const navigate = useNavigate();
    const [userRole, setUserRole] = useState(null);

    // Fetch user role from Firestore
    useEffect(() => {
        const fetchUserRole = async () => {
            if (user) {
                const userDocRef = doc(db, "users", user.uid);
                const userDocSnap = await getDoc(userDocRef);
                if (userDocSnap.exists()) {
                    const userData = userDocSnap.data();
                    setUserRole(userData.role);
                }
            }
        };
        fetchUserRole();
    }, [user]);

    const handleLogout = async () => {
        try {
            await signOutUser();
            console.log("User logged out");
            navigate("/"); // Redirect to home after logout
        } catch (error) {
            console.error("Logout Error:", error.message);
        }
    };

    // Navigate to the appropriate dashboard
    const handleDashboardRedirect = (role) => {
        if (role === 'admin') {
            navigate("/admin");
        } else if (role === 'supplier') {
            navigate("/supplier");
        }
    };

    return (
        <header className="App-header">
            <div className="header-content">
                <h1 className="site-title">HikeGear Hub</h1>
                <div className="auth-links">
                    {user ? (
                        <>
                            {/* Display a dashboard button based on the role */}
                            {userRole && userRole !== 'admin' && (
                                <button
                                    className="user-dashboard-button"
                                    onClick={() => navigate(`/${userRole}-dashboard`)}
                                >
                                    User Dashboard
                                </button>
                            )}

                            {userRole === 'admin' && (
                                <button
                                    className="admin-dashboard-button"
                                    onClick={() => handleDashboardRedirect('admin')}
                                >
                                    Admin Dashboard
                                </button>
                            )}

                            <button onClick={handleLogout} className="logout-button">
                                Log Out
                            </button>
                        </>
                    ) : (
                        <>
                            <button onClick={() => navigate("/signin")} className="auth-button">Sign In</button>
                            <button onClick={() => navigate("/signup")} className="auth-button">Sign Up</button>
                        </>
                    )}
                </div>
            </div>
        </header>
    );
}

export default Header;
